+const LONG_PRESS_KEYBOARD_MS = 420;
+const LONG_PRESS_MOVE_PX = 14;
+let pendingKeyboardLongPress = null;
+
+function cancelKeyboardLongPressTracker() {
+  if (!pendingKeyboardLongPress) return false;
+  const { timerId, triggered } = pendingKeyboardLongPress;
+  clearTimeout(timerId);
+  pendingKeyboardLongPress = null;
+  return triggered;
+}
+
+function startKeyboardLongPressTracker(pointerId, clientX, clientY) {
+  if (!shouldUseMobileKeyboardProxy() || mobileInputMode !== "touch") return;
+  cancelKeyboardLongPressTracker();
+
+  const tracker = {
+    pointerId,
+    startX: clientX,
+    startY: clientY,
+    triggered: false,
+    timerId: 0,
+  };
+
+  tracker.timerId = window.setTimeout(() => {
+    if (!pendingKeyboardLongPress || pendingKeyboardLongPress !== tracker) return;
+    if (!shouldUseMobileKeyboardProxy() || mobileInputMode !== "touch") return;
+
+    tracker.triggered = true;
+    setMobileInputMode("keyboard", { focusTarget: true });
+
+    if (
+      Number.isFinite(tracker.pointerId) &&
+      typeof runner.panePointerCancel === "function"
+    ) {
+      try {
+        const dispatch = runner.panePointerCancel(tracker.pointerId);
+        applyPaneCaptureCommand(dispatch, { skipAcquireAck: true });
+      } catch (_) {}
+    }
+    paneActivePointers.delete(tracker.pointerId);
+    paneTouchPointers.delete(tracker.pointerId);
+    touchGestureSuppressedByPane = false;
+    touchState = TOUCH_IDLE;
+    touchScrollAccX = 0;
+    touchScrollAccY = 0;
+    pinchStartDist = 0;
+    syncPaneOverlayFromRunner();
+  }, LONG_PRESS_KEYBOARD_MS);
+
+  pendingKeyboardLongPress = tracker;
+}
+
+function updateKeyboardLongPressTracker(clientX, clientY) {
+  if (!pendingKeyboardLongPress || pendingKeyboardLongPress.triggered) return;
+  const dx = clientX - pendingKeyboardLongPress.startX;
+  const dy = clientY - pendingKeyboardLongPress.startY;
+  if (Math.hypot(dx, dy) > LONG_PRESS_MOVE_PX) {
+    cancelKeyboardLongPressTracker();
+  }
+}
